INSERT INTO position_questions (categoryId, questionNumber, questionText, `order`) VALUES (8, '49', 'Bulunduğu şubeye özel satışı arttıracak alternatif öneriler sunar. Müşteri geri bildirimlerini paylaşır.', 49);
